// Multi-split greedy: when removing target k, split the above-block so that
// soon-needed boxes end up ON TOP of their destination stacks.
// Each split costs +1 energy but saves moving those boxes again later.

const double TIME_LIMIT = 1.95;
auto GLOBAL_START = std::chrono::steady_clock::now();

struct RNG {
    std::mt19937 rng;
    RNG() : rng(std::chrono::steady_clock::now().time_since_epoch().count()) {}
    int randint(int lo, int hi) {
        return std::uniform_int_distribution<int>(lo, hi)(rng);
    }
    double randdbl() {
        return std::uniform_real_distribution<double>(0.0, 1.0)(rng);
    }
} rng;

double elapsed() {
    return std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START).count();
}

struct Sim {
    int N, M;
    std::vector<std::vector<int>> stacks; // stacks[i][j] = box value (0-indexed)
    std::vector<int> box_stack; // which stack is box in
    std::vector<int> box_height; // height within stack
    std::vector<std::pair<int,int>> ops;
    long long energy;

    Sim() : N(0), M(0), energy(0) {}

    void init(int n, int m, const std::vector<std::vector<int>>& init_stacks) {
        N = n; M = m; energy = 0;
        stacks = init_stacks;
        box_stack.resize(N);
        box_height.resize(N);
        ops.clear();
        ops.reserve(N * 4);
        for (int i = 0; i < M; i++) {
            for (int j = 0; j < (int)stacks[i].size(); j++) {
                box_stack[stacks[i][j]] = i;
                box_height[stacks[i][j]] = j;
            }
        }
    }

    void move_block(int box_val, int dest) {
        // Move box_val and everything above it to dest
        int src = box_stack[box_val];
        int h = box_height[box_val];
        int num_moved = (int)stacks[src].size() - h;

        int dest_h = (int)stacks[dest].size();
        for (int i = h; i < (int)stacks[src].size(); i++) {
            int b = stacks[src][i];
            box_stack[b] = dest;
            box_height[b] = dest_h + (i - h);
            stacks[dest].push_back(b);
        }
        stacks[src].resize(h);

        energy += num_moved + 1;
        ops.push_back({box_val + 1, dest + 1}); // 1-indexed output
    }

    void carry_out(int box_val) {
        int src = box_stack[box_val];
        stacks[src].pop_back();
        ops.push_back({box_val + 1, 0});
    }

    int top_of_stack(int s) const {
        if (stacks[s].empty()) return -1;
        return stacks[s].back();
    }
};

// Score a destination for placing a block. Lower = better.
double score_dest(const Sim& sim, int dest, const std::vector<int>& block, int current_target) {
    if (dest < 0 || dest >= sim.M) return 1e18;
    const auto& dst = sim.stacks[dest];
    double score = 0.0;

    int block_min = *std::min_element(block.begin(), block.end());

    // Heavy penalty for covering soon-needed boxes
    for (int b : dst) {
        if (b < block_min) {
            // b is needed before our block's most urgent box
            // Penalty proportional to how soon b is needed and how much we're piling on
            double urgency = (double)(block_min - b);
            score += urgency * 2.0 + (double)block.size() * 1.5;
        }
    }

    // Penalty for stack height (taller stacks more likely to cause problems)
    score += (double)dst.size() * 0.3;

    // Bonus if all dest boxes have value > all block boxes (no conflicts)
    if (!dst.empty()) {
        int dest_min = *std::min_element(dst.begin(), dst.end());
        if (dest_min > *std::max_element(block.begin(), block.end())) {
            score -= 50.0; // Big bonus - this is a great destination
        }
    } else {
        // Empty stack - good for urgent items, but a limited resource
        if (block_min <= current_target + 20) {
            score -= 30.0; // Good for urgent boxes
        } else {
            score -= 5.0; // Less valuable for non-urgent
        }
    }

    // Small bonus for putting block with similar range boxes
    if (!dst.empty()) {
        int dest_min = *std::min_element(dst.begin(), dst.end());
        int dest_max = *std::max_element(dst.begin(), dst.end());
        int block_max = *std::max_element(block.begin(), block.end());
        // If block fits "above" dest range (block values > dest values), that's good
        // because block items are needed later
        if (block_min > dest_max) {
            score -= 10.0;
        }
    }

    return score;
}

int best_dest_for_block(const Sim& sim, const std::vector<int>& block, int current_target, int exclude_stack) {
    double best_score = 1e18;
    int best_d = -1;
    for (int d = 0; d < sim.M; d++) {
        if (d == exclude_stack) continue;
        double s = score_dest(sim, d, block, current_target);
        if (s < best_score) {
            best_score = s;
            best_d = d;
        }
    }
    return best_d;
}

// Run multi-split greedy
long long run_greedy(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                     std::vector<std::pair<int,int>>& out_ops, int max_splits_per_removal) {
    Sim sim;
    sim.init(N, M, init_stacks);

    for (int k = 0; k < N; k++) {
        int src = sim.box_stack[k];
        int h = sim.box_height[k];

        if (h == (int)sim.stacks[src].size() - 1) {
            // k is on top, just carry out
            sim.carry_out(k);
            continue;
        }

        // Get the above-block
        int above_count = (int)sim.stacks[src].size() - 1 - h;

        // Find critical boxes in above-block (those needed soonest)
        // Collect boxes above target with their positions
        struct AboveBox { int val; int pos; }; // pos = index in stack
        std::vector<AboveBox> above;
        above.reserve(above_count);
        for (int i = h + 1; i < (int)sim.stacks[src].size(); i++) {
            above.push_back({sim.stacks[src][i], i});
        }

        // Find split points: positions of the most urgent boxes (lowest values)
        // We want these to end up on top of their destinations
        std::vector<int> critical_positions; // positions in stack where we want to split

        // Sort above by value to find the most urgent ones
        std::vector<int> above_sorted_by_val;
        above_sorted_by_val.reserve(above_count);
        for (auto& ab : above) above_sorted_by_val.push_back(ab.val);
        std::sort(above_sorted_by_val.begin(), above_sorted_by_val.end());

        // Determine how many splits to do
        // A box is worth splitting if it's needed within the next threshold steps
        int threshold = std::min(N - k, 40);

        // Find critical boxes in the above-block that are within threshold
        // and identify split points (from top to bottom)
        std::vector<int> split_at_positions; // stack positions to split at (descending order)

        for (int i = (int)above.size() - 1; i >= 0; i--) {
            if (above[i].val < k + threshold && above[i].val != k) {
                // This box is needed soon
                // Check if it's worth splitting: only if there are boxes above it in current state
                if (i < (int)above.size() - 1) {
                    // There are boxes above this one - it would benefit from being on top
                    split_at_positions.push_back(above[i].pos);
                }
            }
        }

        // Limit number of splits
        // Sort split positions in descending order (top to bottom processing)
        std::sort(split_at_positions.begin(), split_at_positions.end(), std::greater<int>());

        // Remove duplicates and limit
        split_at_positions.erase(
            std::unique(split_at_positions.begin(), split_at_positions.end()),
            split_at_positions.end());

        if ((int)split_at_positions.size() > max_splits_per_removal) {
            // Keep only the most urgent ones (those with lowest box values)
            // Re-sort by box value (ascending = most urgent first), then take first max_splits
            std::sort(split_at_positions.begin(), split_at_positions.end(),
                [&](int pos_a, int pos_b) {
                    return sim.stacks[src][pos_a] < sim.stacks[src][pos_b];
                });
            split_at_positions.resize(max_splits_per_removal);
            // Re-sort descending by position for top-down processing
            std::sort(split_at_positions.begin(), split_at_positions.end(), std::greater<int>());
        }

        // Execute splits from top down
        // Strategy: for each split point p, move everything from p+1 upward to a dest,
        // leaving the box at p on top of remaining stack.
        // Then finally move the entire remaining above-block (with most urgent on top) to a dest.

        if (split_at_positions.empty()) {
            // No beneficial splits - just do single move
            int first_above = sim.stacks[src][h + 1];
            std::vector<int> block(sim.stacks[src].begin() + h + 1, sim.stacks[src].end());
            int dest = best_dest_for_block(sim, block, k, src);
            sim.move_block(first_above, dest);
        } else {
            // Process splits from top down
            for (int sp : split_at_positions) {
                // Move everything above position sp to a destination
                if (sp + 1 < (int)sim.stacks[src].size()) {
                    int top_box = sim.stacks[src][sp + 1];
                    std::vector<int> top_block(sim.stacks[src].begin() + sp + 1, sim.stacks[src].end());
                    int dest = best_dest_for_block(sim, top_block, k, src);
                    sim.move_block(top_box, dest);
                }
            }

            // Now move remaining above-target block
            // The most urgent box should be on top after splits
            if (h + 1 < (int)sim.stacks[src].size()) {
                int first_above = sim.stacks[src][h + 1];
                std::vector<int> remaining(sim.stacks[src].begin() + h + 1, sim.stacks[src].end());
                int dest = best_dest_for_block(sim, remaining, k, src);
                sim.move_block(first_above, dest);
            }
        }

        // Carry out k
        sim.carry_out(k);
    }

    out_ops = sim.ops;
    return sim.energy;
}

// Run simple greedy (single move, for comparison / SA baseline)
long long run_simple_greedy(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                            const std::vector<int>& dest_choices,
                            std::vector<std::pair<int,int>>& out_ops) {
    Sim sim;
    sim.init(N, M, init_stacks);

    for (int k = 0; k < N; k++) {
        int src = sim.box_stack[k];
        int h = sim.box_height[k];

        if (h == (int)sim.stacks[src].size() - 1) {
            sim.carry_out(k);
            continue;
        }

        int first_above = sim.stacks[src][h + 1];
        int dest = dest_choices[k];
        if (dest == src) dest = (src + 1) % M;
        sim.move_block(first_above, dest);
        sim.carry_out(k);
    }

    out_ops = sim.ops;
    return sim.energy;
}

// SA over single-move destinations
long long run_sa_single(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                        std::vector<int>& best_dests, double time_budget) {
    // Generate initial plan using single-move greedy with heuristic
    std::vector<int> plan(N);
    {
        Sim sim;
        sim.init(N, M, init_stacks);
        for (int k = 0; k < N; k++) {
            int src = sim.box_stack[k];
            int h = sim.box_height[k];
            if (h == (int)sim.stacks[src].size() - 1) {
                plan[k] = src;
                sim.carry_out(k);
                continue;
            }
            int first_above = sim.stacks[src][h + 1];
            std::vector<int> block(sim.stacks[src].begin() + h + 1, sim.stacks[src].end());
            int dest = best_dest_for_block(sim, block, k, src);
            plan[k] = dest;
            sim.move_block(first_above, dest);
            sim.carry_out(k);
        }
    }

    // Evaluate initial plan
    auto eval_plan = [&](const std::vector<int>& p) -> long long {
        Sim sim;
        sim.init(N, M, init_stacks);
        for (int k = 0; k < N; k++) {
            int src = sim.box_stack[k];
            int h = sim.box_height[k];
            if (h == (int)sim.stacks[src].size() - 1) {
                sim.carry_out(k);
                continue;
            }
            int first_above = sim.stacks[src][h + 1];
            int dest = p[k];
            if (dest == src) dest = (src + 1) % M;
            sim.move_block(first_above, dest);
            sim.carry_out(k);
        }
        return sim.energy;
    };

    long long cur_energy = eval_plan(plan);
    best_dests = plan;
    long long best_energy = cur_energy;

    double t_start = elapsed();
    double T_init = 50.0, T_final = 0.1;
    int max_block = std::max(1, N / 10);

    while (true) {
        double now = elapsed();
        if (now >= t_start + time_budget) break;
        double progress = (now - t_start) / time_budget;
        double T = T_init * std::pow(T_final / T_init, progress);

        std::vector<int> new_plan = plan;

        // Perturbation
        double r = rng.randdbl();
        if (r < 0.4) {
            int idx = rng.randint(0, N - 1);
            new_plan[idx] = rng.randint(0, M - 1);
        } else if (r < 0.8) {
            int start = rng.randint(0, N - 1);
            int len = rng.randint(1, max_block);
            for (int i = 0; i < len; i++) {
                int idx = (start + i) % N;
                new_plan[idx] = rng.randint(0, M - 1);
            }
        } else {
            // Swap two destinations
            int i1 = rng.randint(0, N - 1);
            int i2 = rng.randint(0, N - 1);
            std::swap(new_plan[i1], new_plan[i2]);
        }

        long long new_energy = eval_plan(new_plan);
        long long delta = new_energy - cur_energy;

        if (delta <= 0 || rng.randdbl() < std::exp(-(double)delta / T)) {
            cur_energy = new_energy;
            plan = new_plan;
            if (cur_energy < best_energy) {
                best_energy = cur_energy;
                best_dests = plan;
            }
        }
    }

    return best_energy;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;

    std::vector<std::vector<int>> init_stacks(M);
    for (int i = 0; i < M; i++) {
        init_stacks[i].resize(N / M);
        for (int j = 0; j < N / M; j++) {
            std::cin >> init_stacks[i][j];
            init_stacks[i][j]--; // 0-indexed
        }
    }

    // Strategy 1: Multi-split greedy with various split limits
    std::vector<std::pair<int,int>> best_ops;
    long long best_energy = 1e18;

    for (int max_splits = 1; max_splits <= 4; max_splits++) {
        std::vector<std::pair<int,int>> ops;
        long long e = run_greedy(init_stacks, N, M, ops, max_splits);
        if (e < best_energy) {
            best_energy = e;
            best_ops = ops;
        }
    }

    // Strategy 2: Single-move SA (use remaining time)
    double remaining_time = TIME_LIMIT - elapsed() - 0.05;
    if (remaining_time > 0.3) {
        std::vector<int> sa_dests;
        long long sa_energy = run_sa_single(init_stacks, N, M, sa_dests, remaining_time);
        if (sa_energy < best_energy) {
            best_energy = sa_energy;
            best_ops.clear();
            // Reconstruct ops from sa_dests
            Sim sim;
            sim.init(N, M, init_stacks);
            for (int k = 0; k < N; k++) {
                int src = sim.box_stack[k];
                int h = sim.box_height[k];
                if (h == (int)sim.stacks[src].size() - 1) {
                    sim.carry_out(k);
                    continue;
                }
                int first_above = sim.stacks[src][h + 1];
                int dest = sa_dests[k];
                if (dest == src) dest = (src + 1) % M;
                sim.move_block(first_above, dest);
                sim.carry_out(k);
            }
            best_ops = sim.ops;
        }
    }

    // Output
    for (auto& [v, i] : best_ops) {
        std::cout << v << " " << i << "\n";
    }

    return 0;
}
