        int src = box_stack[box_val];
        int h = box_height[box_val];
        int num_moved = (int)stacks[src].size() - h;

        int dest_h = (int)stacks[dest].size();
        for (int i = h; i < (int)stacks[src].size(); i++) {
            int b = stacks[src][i];
            box_stack[b] = dest;
            box_height[b] = dest_h + (i - h);
            stacks[dest].push_back(b);
        }
