// Score destination for a block. Lower = better.
double score_dest(const Sim& sim, int dest, const std::vector<int>& block, int current_target, int src_stack) {
    if (dest == src_stack) return 1e18;
    const auto& dst = sim.stacks[dest];
    double score = 0.0;

    int block_min = block[0];
    int block_max = block[0];
    for (int b : block) {
        block_min = std::min(block_min, b);
        block_max = std::max(block_max, b);
    }

    // Penalize covering soon-needed boxes in destination
    for (int b : dst) {
        if (b >= current_target && b < block_min) {
            // b is needed before any box in block
            int depth_after = (int)block.size(); // how many boxes will be on top of b
            score += (double)depth_after * 3.0;
        }
    }
    // Check if top of dest is needed soon
    if (!dst.empty()) {
        int top = dst.back();
        if (top >= current_target && top < current_target + 5) {
            score += 50.0; // Don't cover immediately needed box
        }
    }

    // Bonus for empty stack (but limited resource)
    if (dst.empty()) {
        score -= 20.0;
    } else {
        // Slight height penalty
        score += (double)dst.size() * 0.2;

        // Bonus if block min > all dest values (block on top is fine, needed later)
        int dest_max = *std::max_element(dst.begin(), dst.end());
        if (block_min > dest_max) {
            score -= 15.0;
        }
    }

    return score;
}

