        if (d == src) continue;
        double s = score_dest(sim, d, block, current_target, src);
        if (s < best_s) {
            best_s = s;
            best_d = d;
        }
    }
    return best_d;
}

// Multi-split greedy: when boxes above target, split intelligently
long long run_greedy_split(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                           std::vector<std::pair<int,int>>& out_ops, int max_splits) {
    Sim sim;
    sim.init(N, M, init_stacks);

    for (int k = 0; k < N; k++) {
        int src = sim.box_stack[k];
        int h = sim.box_height[k];

        if (h == (int)sim.stacks[src].size() - 1) {
            sim.carry_out(k);
            continue;
        }

        int above_count = (int)sim.stacks[src].size() - 1 - h;

        // Identify split opportunities:
        // Find boxes in above-block that are needed soon and have stuff on top of them.
        // Splitting at a critical box means moving what's above it separately,
        // leaving the critical box on top so it's cheaper to access later.

        // Collect above boxes (bottom-up from h+1)
        std::vector<int> above;
        above.reserve(above_count);
        for (int i = h + 1; i < (int)sim.stacks[src].size(); i++) {
            above.push_back(sim.stacks[src][i]);
        }

        // Find beneficial split points: positions in 'above' where we should split
        // A split at position p means: move above[p+1..end] first, then move above[0..p]
        // This costs extra energy but keeps above[p] on top of its destination

        // Only split if the box at split point is needed soon
        std::vector<int> split_candidates; // indices in 'above'
        for (int i = 0; i < (int)above.size() - 1; i++) {
            int box_val = above[i];
            // Check if this box is needed within a window
            if (box_val >= k + 1 && box_val < k + 30) {
                // Count how many boxes are above it in the current above-block
                int boxes_above = (int)above.size() - 1 - i;
                // A split saves us from having to move these boxes_above boxes later
                // Cost of split: need an extra move operation (boxes_above boxes + 1 energy)
                // Potential savings: when box_val becomes target, we won't need to move as much
                // Heuristic: split if box is needed soon and many boxes above it
                if (boxes_above >= 2 && box_val < k + 15) {
                    split_candidates.push_back(i);
                }
            }
        }

        // Sort by urgency (lowest box value = most urgent)
        std::sort(split_candidates.begin(), split_candidates.end(),
            [&](int a, int b) { return above[a] < above[b]; });

        // Limit splits
        if ((int)split_candidates.size() > max_splits) {
            split_candidates.resize(max_splits);
        }
        // Sort by position descending (process from top)
        std::sort(split_candidates.begin(), split_candidates.end(), std::greater<int>());

        if (split_candidates.empty()) {
            // Single move
            std::vector<int> block(sim.stacks[src].begin() + h + 1, sim.stacks[src].end());
            int first_above = sim.stacks[src][h + 1];
            int dest = best_dest(sim, block, k, src);
            sim.move_block(first_above, dest);
        } else {
            // Execute splits from top of stack downward
            for (int sp_idx : split_candidates) {
                int stack_pos = h + 1 + sp_idx + 1; // position in stack of first box to move
                if (stack_pos < (int)sim.stacks[src].size()) {
                    int top_box = sim.stacks[src][stack_pos];
                    std::vector<int> block(sim.stacks[src].begin() + stack_pos, sim.stacks[src].end());
                    int dest = best_dest(sim, block, k, src);
                    sim.move_block(top_box, dest);
                }
            }
            // Move remaining above-block
            if (h + 1 < (int)sim.stacks[src].size()) {
                int first_above = sim.stacks[src][h + 1];
                std::vector<int> remaining(sim.stacks[src].begin() + h + 1, sim.stacks[src].end());
                int dest = best_dest(sim, remaining, k, src);
                sim.move_block(first_above, dest);
            }
        }

        sim.carry_out(k);
    }

    out_ops = sim.ops;
    return sim.energy;
}

// SA over single-move plan
long long run_sa(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                 std::vector<std::pair<int,int>>& out_ops, double time_budget) {
    // Generate initial greedy plan
    std::vector<int> plan(N);
    {
        Sim sim;
        sim.init(N, M, init_stacks);
        for (int k = 0; k < N; k++) {
            int src = sim.box_stack[k];
            int h = sim.box_height[k];
            if (h == (int)sim.stacks[src].size() - 1) {
                plan[k] = src;
                sim.carry_out(k);
                continue;
            }
            int first_above = sim.stacks[src][h + 1];
            std::vector<int> block(sim.stacks[src].begin() + h + 1, sim.stacks[src].end());
            int dest = best_dest(sim, block, k, src);
            plan[k] = dest;
            sim.move_block(first_above, dest);
            sim.carry_out(k);
        }
    }

    auto eval_plan = [&](const std::vector<int>& p) -> long long {
        Sim sim;
        sim.init(N, M, init_stacks);
        for (int k = 0; k < N; k++) {
            int src = sim.box_stack[k];
            int h = sim.box_height[k];
            if (h == (int)sim.stacks[src].size() - 1) {
                sim.carry_out(k);
                continue;
            }
            int first_above = sim.stacks[src][h + 1];
            int dest = p[k];
            if (dest == src) dest = (src + 1) % M;
            sim.move_block(first_above, dest);
            sim.carry_out(k);
        }
        return sim.energy;
    };

    long long cur_energy = eval_plan(plan);
    std::vector<int> best_plan = plan;
    long long best_energy = cur_energy;

    double t_start = elapsed();
    double T_init = 60.0, T_final = 0.05;
    int max_block = std::max(1, N / 12);

    while (true) {
        double now = elapsed();
        if (now >= t_start + time_budget) break;
        double progress = (now - t_start) / time_budget;
        double T = T_init * std::pow(T_final / T_init, progress);

        std::vector<int> new_plan = plan;

        double r = rng.randdbl();
        if (r < 0.45) {
            int idx = rng.randint(0, N - 1);
            new_plan[idx] = rng.randint(0, M - 1);
        } else if (r < 0.85) {
            int start = rng.randint(0, N - 1);
            int len = rng.randint(1, max_block);
            for (int i = 0; i < len; i++) {
                int idx = (start + i) % N;
                new_plan[idx] = rng.randint(0, M - 1);
            }
        } else {
            int i1 = rng.randint(0, N - 1);
            int i2 = rng.randint(0, N - 1);
            std::swap(new_plan[i1], new_plan[i2]);
        }

        long long new_energy = eval_plan(new_plan);
        long long delta = new_energy - cur_energy;

        if (delta <= 0 || rng.randdbl() < std::exp(-(double)delta / T)) {
            cur_energy = new_energy;
            plan = new_plan;
            if (cur_energy < best_energy) {
                best_energy = cur_energy;
                best_plan = plan;
            }
        }
    }

    // Reconstruct ops from best plan
    Sim sim;
    sim.init(N, M, init_stacks);
    for (int k = 0; k < N; k++) {
        int src = sim.box_stack[k];
        int h = sim.box_height[k];
        if (h == (int)sim.stacks[src].size() - 1) {
            sim.carry_out(k);
            continue;
        }
        int first_above = sim.stacks[src][h + 1];
        int dest = best_plan[k];
        if (dest == src) dest = (src + 1) % M;
        sim.move_block(first_above, dest);
        sim.carry_out(k);
    }
    out_ops = sim.ops;
    return best_energy;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;

    std::vector<std::vector<int>> init_stacks(M);
    for (int i = 0; i < M; i++) {
        init_stacks[i].resize(N / M);
        for (int j = 0; j < N / M; j++) {
            std::cin >> init_stacks[i][j];
            init_stacks[i][j]--;
        }
    }

    std::vector<std::pair<int,int>> best_ops;
    long long best_energy = 1e18;

    // Try multi-split greedy with different split limits
    for (int max_splits = 0; max_splits <= 3; max_splits++) {
        std::vector<std::pair<int,int>> ops;
        long long e = run_greedy_split(init_stacks, N, M, ops, max_splits);
        if (e < best_energy && (int)ops.size() <= 5000) {
            best_energy = e;
            best_ops = ops;
        }
    }

    // SA on single-move plan with remaining time
    double remaining = TIME_LIMIT - elapsed() - 0.05;
    if (remaining > 0.3) {
        std::vector<std::pair<int,int>> sa_ops;
        long long sa_energy = run_sa(init_stacks, N, M, sa_ops, remaining);
        if (sa_energy < best_energy && (int)sa_ops.size() <= 5000) {
            best_energy = sa_energy;
            best_ops = sa_ops;
        }
    }

    for (auto& [v, i] : best_ops) {
        std::cout << v << " " << i << "\n";
    }

    return 0;
}
