        for (int k = 0; k < N; k++) {
            int src = sim.box_stack[k];
            int h = sim.box_height[k];
            if (h == sim.stack_sz[src] - 1) {
                plan[k] = src;
                sim.carry_out(k);
                continue;
            }
            plan[k] = greedy_best_dest(sim, k, src, M);
            int first_above = sim.stack_data[src][h + 1];
            int dest = plan[k];
            if (dest == src) dest = (src + 1) % M;
            sim.move_above(first_above, dest);
            sim.carry_out(k);
        }
    }

    long long cur_energy = eval_plan(init_stacks, plan, N, M);
    int best_plan[MAXN];
    for (int i = 0; i < N; i++) best_plan[i] = plan[i];
    long long best_energy = cur_energy;

    // SA with full re-evaluation (fast due to array-based sim)
    double T_init = 60.0, T_final = 0.05;
    int max_block = std::max(1, N / 10);
    double sa_start = elapsed();
    double sa_budget = TIME_LIMIT - sa_start - 0.03;

    int new_plan[MAXN];
    long long iter_count = 0;

    while (true) {
        double now = elapsed();
        if (now >= sa_start + sa_budget) break;
        double progress = (now - sa_start) / sa_budget;
        double T = T_init * std::pow(T_final / T_init, progress);

        for (int i = 0; i < N; i++) new_plan[i] = plan[i];

        // Perturbation
        double r = rng.randdbl();
        if (r < 0.45) {
            int idx = rng.randint(0, N - 1);
            new_plan[idx] = rng.randint(0, M - 1);
        } else if (r < 0.85) {
            int start = rng.randint(0, N - 1);
            int len = rng.randint(1, max_block);
            for (int i = 0; i < len; i++) {
                int idx = (start + i) % N;
                new_plan[idx] = rng.randint(0, M - 1);
            }
        } else {
            int i1 = rng.randint(0, N - 1);
            int i2 = rng.randint(0, N - 1);
            std::swap(new_plan[i1], new_plan[i2]);
        }

        long long new_energy = eval_plan(init_stacks, new_plan, N, M);
        long long delta = new_energy - cur_energy;

        if (delta <= 0 || rng.randdbl() < std::exp(-(double)delta / T)) {
            cur_energy = new_energy;
            for (int i = 0; i < N; i++) plan[i] = new_plan[i];
            if (cur_energy < best_energy) {
                best_energy = cur_energy;
                for (int i = 0; i < N; i++) best_plan[i] = plan[i];
            }
        }
        iter_count++;
    }

    // Reconstruct and output
    FastSim sim;
    sim.init(N, M, init_stacks);
    std::vector<std::pair<int,int>> ops;
    ops.reserve(N * 2);
    for (int k = 0; k < N; k++) {
        int src = sim.box_stack[k];
        int h = sim.box_height[k];
        if (h == sim.stack_sz[src] - 1) {
            sim.carry_out(k);
            ops.push_back({k + 1, 0});
            continue;
        }
        int first_above = sim.stack_data[src][h + 1];
        int dest = best_plan[k];
        if (dest == src) dest = (src + 1) % M;
        sim.move_above(first_above, dest);
        ops.push_back({first_above + 1, dest + 1});
        sim.carry_out(k);
        ops.push_back({k + 1, 0});
    }

    for (auto& [v, i] : ops) {
        std::cout << v << " " << i << "\n";
    }

    return 0;
}
